1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	export function quote(input: { customer: { yearsInsured: number; previousContracts: number }; items: Array<{ type: string; cursed?: boolean; enchantment?: number }> }): { premium: number } {
16	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
17	
18	  for (const item of input.items) {
19	    if (!(item.type in BASE_PREMIUMS)) {
20	      throw new Error(`Unknown item type: ${item.type}`);
21	    }
22	  }
23	
24	  const componentCounts: Record<string, number> = {};
25	  let base = 0;
26	  let itemSubtotal = 0;
27	  for (const item of input.items) {
28	    if (COMPONENT_TYPES.has(item.type)) {
29	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
30	    } else {
31	      const itemBase = BASE_PREMIUMS[item.type];
32	      base += itemBase;
33	      itemSubtotal += itemBase + (item.cursed ? 0.5 * itemBase : 0) + ((item.enchantment ?? 0) >= 5 ? 0.3 * itemBase : 0);
34	    }
35	  }
36	  for (const [type, count] of Object.entries(componentCounts)) {
37	    const componentBase = count === 3 ? 60 : count * BASE_PREMIUMS[type];
38	    base += componentBase;
39	    itemSubtotal += componentBase;
40	  }
41	
42	  const loyalty = input.customer.yearsInsured >= 2 ? -0.2 * base : 0;
43	  const followUp = input.customer.previousContracts >= 1 ? -0.15 * base : 0;
44	  return { premium: Math.ceil(itemSubtotal + base * FIRST_INSURANCE_RATE + loyalty + followUp + PROCESSING_FEE) };
45	}
46	
47	const INSURANCE_VALUES: Record<string, number> = {
48	  sword: 1000,
49	  amulet: 600,
50	  staff: 800,
51	  potion: 400,
52	  rune: 250,
53	  moonstone: 250,
54	};
55	
56	export function claim(input: { items: Array<{ type: string; material?: string; enchantment?: number }>; damages: Array<{ itemType: string; amount: number }>; priorPaid?: number }): { payout: number; remainingCap: number } {
57	  for (const damage of input.damages) {
58	    if (damage.amount < 0) {
59	      throw new Error(`negative damage amount`);
60	    }
61	  }
62	  const itemCounts: Record<string, number> = {};
63	  for (const item of input.items) {
64	    itemCounts[item.type] = (itemCounts[item.type] ?? 0) + 1;
65	  }
66	  const damageCounts: Record<string, number> = {};
67	  for (const damage of input.damages) {
68	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
69	  }
70	  for (const [type, count] of Object.entries(damageCounts)) {
71	    if (count > (itemCounts[type] ?? 0)) {
72	      throw new Error(`more ${type} damages than insured`);
